// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract MyNFT is ERC721, Ownable {
    uint256 public nextTokenId;
    string private _baseTokenURI;

    event BaseURIUpdated(string newBaseURI);
    event Minted(address indexed to, uint256 indexed tokenId);

    constructor(
        string memory name_,
        string memory symbol_,
        string memory baseTokenURI_
    ) ERC721(name_, symbol_) {
        _baseTokenURI = baseTokenURI_;
    }

    function mint(address to) external onlyOwner returns (uint256 tokenId) {
        require(to != address(0), "Invalid recipient");

        tokenId = ++nextTokenId;
        _safeMint(to, tokenId);

        emit Minted(to, tokenId);
    }

    function setBaseURI(string calldata newBaseTokenURI) external onlyOwner {
        _baseTokenURI = newBaseTokenURI;
        emit BaseURIUpdated(newBaseTokenURI);
    }

    function _baseURI() internal view override returns (string memory) {
        return _baseTokenURI;
    }
}

contracts/NFTStaking.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC721/IERC721.sol";
import "@openzeppelin/contracts/token/ERC721/IERC721Receiver.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/security/Pausable.sol";

contract NFTStaking is Ownable, ReentrancyGuard, Pausable, IERC721Receiver {
    using SafeERC20 for IERC20;

    struct StakePosition {
        address owner;
        uint256 stakedAt;
        uint256 lastClaimedAt;
    }

    IERC721 public immutable stakingNFT;
    IERC20 public immutable rewardToken;

    uint256 public rewardRatePerSecond;
    uint256 public totalStakedNFTs;

    mapping(uint256 => StakePosition) public stakes;
    mapping(address => uint256) public stakedCountByUser;

    event Staked(address indexed user, uint256 indexed tokenId);
    event Unstaked(address indexed user, uint256 indexed tokenId);
    event RewardClaimed(address indexed user, uint256 amount);
    event RewardRateUpdated(uint256 newRate);
    event RewardsFunded(uint256 amount);

    constructor(address _stakingNFT, address _rewardToken, uint256 _rewardRatePerSecond) {
        require(_stakingNFT != address(0), "Invalid NFT");
        require(_rewardToken != address(0), "Invalid reward token");

        stakingNFT = IERC721(_stakingNFT);
        rewardToken = IERC20(_rewardToken);
        rewardRatePerSecond = _rewardRatePerSecond;
    }

    function stake(uint256[] calldata tokenIds) external nonReentrant whenNotPaused {
        uint256 length = tokenIds.length;
        require(length > 0, "No tokenIds");

        for (uint256 i = 0; i < length; i++) {
            uint256 tokenId = tokenIds[i];
            require(stakes[tokenId].owner == address(0), "Already staked");
            require(stakingNFT.ownerOf(tokenId) == msg.sender, "Not token owner");

            stakes[tokenId] = StakePosition({
                owner: msg.sender,
                stakedAt: block.timestamp,
                lastClaimedAt: block.timestamp
            });

            stakedCountByUser[msg.sender] += 1;
            totalStakedNFTs += 1;

            stakingNFT.safeTransferFrom(msg.sender, address(this), tokenId);
            emit Staked(msg.sender, tokenId);
        }
    }

    function claimRewards(uint256[] calldata tokenIds) external nonReentrant {
        uint256 reward = _claimableRewards(msg.sender, tokenIds);
        require(reward > 0, "No rewards");

        for (uint256 i = 0; i < tokenIds.length; i++) {
            stakes[tokenIds[i]].lastClaimedAt = block.timestamp;
        }

        rewardToken.safeTransfer(msg.sender, reward);
        emit RewardClaimed(msg.sender, reward);
    }

    function unstake(uint256[] calldata tokenIds) external nonReentrant {
        uint256 length = tokenIds.length;
        require(length > 0, "No tokenIds");

        uint256 reward = _claimableRewards(msg.sender, tokenIds);

        for (uint256 i = 0; i < length; i++) {
            uint256 tokenId = tokenIds[i];
            require(stakes[tokenId].owner == msg.sender, "Not staker");

            delete stakes[tokenId];
            stakedCountByUser[msg.sender] -= 1;
            totalStakedNFTs -= 1;

            stakingNFT.safeTransferFrom(address(this), msg.sender, tokenId);
            emit Unstaked(msg.sender, tokenId);
        }

        if (reward > 0) {
            rewardToken.safeTransfer(msg.sender, reward);
            emit RewardClaimed(msg.sender, reward);
        }
    }

    function pendingRewards(address user, uint256[] calldata tokenIds) external view returns (uint256) {
        return _claimableRewards(user, tokenIds);
    }

    function setRewardRate(uint256 newRate) external onlyOwner {
        rewardRatePerSecond = newRate;
        emit RewardRateUpdated(newRate);
    }

    function fundRewards(uint256 amount) external onlyOwner {
        require(amount > 0, "Amount 0");
        rewardToken.safeTransferFrom(msg.sender, address(this), amount);
        emit RewardsFunded(amount);
    }

    function pause() external onlyOwner {
        _pause();
    }

    function unpause() external onlyOwner {
        _unpause();
    }

    function onERC721Received(address, address, uint256, bytes calldata) external pure override returns (bytes4) {
        return IERC721Receiver.onERC721Received.selector;
    }

    function _claimableRewards(address user, uint256[] calldata tokenIds) internal view returns (uint256 totalReward) {
        uint256 length = tokenIds.length;
        require(length > 0, "No tokenIds");

        for (uint256 i = 0; i < length; i++) {
            StakePosition memory position = stakes[tokenIds[i]];
            require(position.owner == user, "Not staker");
            totalReward += (block.timestamp - position.lastClaimedAt) * rewardRatePerSecond;
        }
    }
}

